import{_ as e,o as d,c as r,ao as i}from"./chunks/framework.BSzmyLFO.js";const y=JSON.parse('{"title":"LAPACK / BLAS coverage","description":"","frontmatter":{},"headers":[],"relativePath":"coverage.md","filePath":"coverage.md","lastUpdated":null}'),l={name:"coverage.md"};function a(g,t,s,n,o,h){return d(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="LAPACK-/-BLAS-coverage" tabindex="-1">LAPACK / BLAS coverage <a class="header-anchor" href="#LAPACK-/-BLAS-coverage" aria-label="Permalink to &quot;LAPACK / BLAS coverage {#LAPACK-/-BLAS-coverage}&quot;">​</a></h1><p>This page tracks which <code>LinearAlgebra</code> operations route to PureBLAS after <code>PureBLAS.activate()</code>, and their optimization status.</p><p><strong>Legend</strong></p><ul><li><p><strong>Routes</strong> — the routine forwards to PureBLAS via LBT after <code>activate()</code> (or is composed from routines that do).</p></li><li><p><strong>Optimized</strong> — ✅ perf-gated <code>≥ OpenBLAS</code> on the dev fleet (Zen3/4/5); ⏳ correctness-first (numerically LAPACK-accurate, blocked/SIMD perf tuning is a documented follow-up); — n/a.</p></li><li><p>Element types: <strong>s</strong> = Float32, <strong>d</strong> = Float64, <strong>c</strong> = ComplexF32, <strong>z</strong> = ComplexF64.</p></li></ul><h2 id="BLAS" tabindex="-1">BLAS <a class="header-anchor" href="#BLAS" aria-label="Permalink to &quot;BLAS {#BLAS}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Level</th><th style="text-align:right;">Routines</th><th style="text-align:right;">Types</th><th style="text-align:right;">Routes</th><th style="text-align:right;">Optimized</th></tr></thead><tbody><tr><td style="text-align:right;">BLAS-1</td><td style="text-align:right;">axpy, scal, copy, dot, nrm2, asum, iamax, rot, swap</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">✅</td></tr><tr><td style="text-align:right;">BLAS-1 complex dot</td><td style="text-align:right;">dotu, dotc</td><td style="text-align:right;">c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">✅</td></tr><tr><td style="text-align:right;">BLAS-2</td><td style="text-align:right;">gemv, ger, symv, hemv, trmv, trsv, banded, packed</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">✅</td></tr><tr><td style="text-align:right;">BLAS-3</td><td style="text-align:right;">gemm, symm, hemm, syrk, herk, syr2k, her2k, trmm, trsm</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">✅</td></tr></tbody></table><p>GEMM additionally uses Strassen–Winograd (real) and Karatsuba 3M (complex) above a size crossover — <strong>beats</strong> OpenBLAS at large <code>n</code>.</p><h2 id="LAPACK-—-factorizations-and-solves" tabindex="-1">LAPACK — factorizations &amp; solves <a class="header-anchor" href="#LAPACK-—-factorizations-and-solves" aria-label="Permalink to &quot;LAPACK — factorizations &amp; solves {#LAPACK-—-factorizations-and-solves}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Op</th><th style="text-align:right;">Routines</th><th style="text-align:right;">Types</th><th style="text-align:right;">Routes</th><th style="text-align:right;">Optimized</th></tr></thead><tbody><tr><td style="text-align:right;">Cholesky</td><td style="text-align:right;">potrf, potrs, potri</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">✅</td></tr><tr><td style="text-align:right;">Pivoted Cholesky</td><td style="text-align:right;">pstrf</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">LU</td><td style="text-align:right;">getrf, getrs, getri, gesv</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">✅</td></tr><tr><td style="text-align:right;">QR</td><td style="text-align:right;">geqrf, geqrt, gemqrt, orgqr, ormqr</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">✅</td></tr><tr><td style="text-align:right;">LQ</td><td style="text-align:right;">gelqf, orglq, ormlq</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">QL / RQ</td><td style="text-align:right;">geqlf, gerqf, org/orm ql/rq</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Pivoted QR</td><td style="text-align:right;">geqp3</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">RZ (for gelsy)</td><td style="text-align:right;">tzrzf, ormrz</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Bunch–Kaufman</td><td style="text-align:right;">sytrf, hetrf, sytrs, hetrs</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Indefinite solve/inv</td><td style="text-align:right;">sysv, hesv, sytri, hetri</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Triangular</td><td style="text-align:right;">trtrs, trtri, trcon</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">✅</td></tr><tr><td style="text-align:right;">Condition est.</td><td style="text-align:right;">gecon, pocon, trcon</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Least-squares</td><td style="text-align:right;">gels</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Rank-deficient LS</td><td style="text-align:right;">gelsd, gelsy</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr></tbody></table><h2 id="LAPACK-—-SVD" tabindex="-1">LAPACK — SVD <a class="header-anchor" href="#LAPACK-—-SVD" aria-label="Permalink to &quot;LAPACK — SVD {#LAPACK-—-SVD}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Op</th><th style="text-align:right;">Routines</th><th style="text-align:right;">Types</th><th style="text-align:right;">Routes</th><th style="text-align:right;">Optimized</th></tr></thead><tbody><tr><td style="text-align:right;">SVD (values+vectors)</td><td style="text-align:right;">gesvd, gesdd, gebrd, bdsqr, bdsdc</td><td style="text-align:right;">s/d</td><td style="text-align:right;">✅</td><td style="text-align:right;">✅</td></tr><tr><td style="text-align:right;">SVD complex</td><td style="text-align:right;">gesvd, gesdd (z/c)</td><td style="text-align:right;">c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Generalized SVD</td><td style="text-align:right;">ggsvd, ggsvd3</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅ (rank-deficient)</td><td style="text-align:right;">⏳</td></tr></tbody></table><h2 id="LAPACK-—-eigensolvers" tabindex="-1">LAPACK — eigensolvers <a class="header-anchor" href="#LAPACK-—-eigensolvers" aria-label="Permalink to &quot;LAPACK — eigensolvers {#LAPACK-—-eigensolvers}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Op</th><th style="text-align:right;">Routines</th><th style="text-align:right;">Types</th><th style="text-align:right;">Routes</th><th style="text-align:right;">Optimized</th></tr></thead><tbody><tr><td style="text-align:right;">Symmetric / Hermitian</td><td style="text-align:right;">syev, syevd, syevr, heev*, sytrd, hetrd, stedc, steqr, sterf, ormtr</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Sym-tridiagonal</td><td style="text-align:right;">stev, stegr, stebz, stein</td><td style="text-align:right;">s/d</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Generalized symmetric</td><td style="text-align:right;">sygvd, hegvd</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Nonsymmetric</td><td style="text-align:right;">geev, geevx, gebal, gehrd, hseqr, trevc, gebak</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Schur</td><td style="text-align:right;">gees</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Generalized nonsym (QZ)</td><td style="text-align:right;">ggev, gges, gghrd, hgeqz, tgevc</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Schur reordering</td><td style="text-align:right;">trexc, trsen</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Sylvester / Lyapunov</td><td style="text-align:right;">trsyl</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr></tbody></table><h2 id="LAPACK-—-banded-/-tridiagonal-/-packed" tabindex="-1">LAPACK — banded / tridiagonal / packed <a class="header-anchor" href="#LAPACK-—-banded-/-tridiagonal-/-packed" aria-label="Permalink to &quot;LAPACK — banded / tridiagonal / packed {#LAPACK-—-banded-/-tridiagonal-/-packed}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Op</th><th style="text-align:right;">Routines</th><th style="text-align:right;">Types</th><th style="text-align:right;">Routes</th><th style="text-align:right;">Optimized</th></tr></thead><tbody><tr><td style="text-align:right;">General banded LU</td><td style="text-align:right;">gbtrf, gbtrs</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">General tridiagonal</td><td style="text-align:right;">gtsv, gttrf, gttrs</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">SPD tridiagonal</td><td style="text-align:right;">pttrf, pttrs, ptsv</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Banded Cholesky</td><td style="text-align:right;">pbtrf, pbtrs</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr><tr><td style="text-align:right;">Packed Cholesky</td><td style="text-align:right;">pptrf, pptrs</td><td style="text-align:right;">s/d/c/z</td><td style="text-align:right;">✅</td><td style="text-align:right;">⏳</td></tr></tbody></table><h2 id="Free-via-composition" tabindex="-1">Free via composition <a class="header-anchor" href="#Free-via-composition" aria-label="Permalink to &quot;Free via composition {#Free-via-composition}&quot;">​</a></h2><p><code>exp</code>, <code>sqrt</code>, <code>log</code>, <code>^</code> of a matrix, <code>sylvester</code>/<code>lyap</code>, <code>pinv</code>, <code>nullspace</code>, <code>rank</code>, <code>cond</code>, <code>factorize</code> — computed in Julia on top of the routed <code>eigen</code>/<code>schur</code>/<code>svd</code>/<code>\\</code> kernels; no separate LAPACK wrapper needed.</p><h2 id="OpenBLAS-fallthrough:-ZERO" tabindex="-1">OpenBLAS fallthrough: ZERO <a class="header-anchor" href="#OpenBLAS-fallthrough:-ZERO" aria-label="Permalink to &quot;OpenBLAS fallthrough: ZERO {#OpenBLAS-fallthrough:-ZERO}&quot;">​</a></h2><p><strong>Every LAPACK symbol <code>LinearAlgebra</code> can <code>ccall</code> now forwards to PureBLAS after <code>activate()</code></strong> — including the auxiliaries (<code>larf</code>/<code>larfg</code>/<code>lacpy</code>), the driver internals (<code>gebrd</code>/<code>bdsqr</code>/<code>bdsdc</code>/<code>hseqr</code>/<code>trevc</code>/<code>gebak</code>/<code>sytrd</code>/<code>hetrd</code>/<code>orgtr</code>/<code>ormtr</code>), the combined and expert drivers (<code>gesv</code>, <code>posv</code>, <strong><code>gesvx</code></strong> with equilibration + iterative refinement + condition/error bounds), the reordering routines (<code>trexc</code>/<code>trsen</code>/<strong><code>tgsen</code></strong>, real <em>and</em> complex — the real path does the 2×2 conjugate-pair swap), <strong><code>trrfs</code></strong>, <strong><code>syconv</code></strong>, complex <strong><code>bdsqr</code></strong>, and the <strong>rank-deficient generalized SVD</strong> (<code>ggsvd</code>, all s/d/c/z). This is enforced by a machine-checkable ratchet test (<code>test/lbt_forward_tests.jl</code>) that enumerates every symbol the stdlib wraps and asserts the fallthrough count is <strong>0</strong>.</p><p>The only two names excluded from the count are <code>cstev_</code>/<code>zstev_</code>, which are <strong>not real LAPACK symbols</strong> — they appear only in commented-out lines of the stdlib and have no OpenBLAS export.</p><h2 id="Summary" tabindex="-1">Summary <a class="header-anchor" href="#Summary" aria-label="Permalink to &quot;Summary {#Summary}&quot;">​</a></h2><ul><li><p><strong>BLAS 1/2/3 and the core dense factorizations (Cholesky, LU, QR, SVD real+complex+F32) are routed AND perf-gated <code>≥ OpenBLAS</code>.</strong></p></li><li><p><strong>Everything else routable through the <code>LinearAlgebra</code> API</strong> — all eigensolvers (symmetric, Hermitian, nonsymmetric, generalized, Schur), Sylvester/Schur-reordering, the expert general solver (<code>gesvx</code>), generalized SVD, and the remaining factorizations (indefinite, QL/RQ, RZ, pivoted Cholesky, banded/tridiagonal/packed, rank-deficient LS) — <strong>is routed and numerically LAPACK-accurate, correctness-first</strong>. The <code>≥ OpenBLAS</code> performance gate for this second tier (blocked <code>dlaqr0</code> multishift+AED, blocked <code>dlahr2</code>, SIMD Bunch-Kaufman/QZ, blocked complex <code>zunmbr</code>, a convergent perf <code>dbdsqr</code>, …) is a scheduled follow-up campaign.</p></li><li><p>The coverage audit (the ratchet gate) confirms <strong>zero OpenBLAS fallthrough</strong>: after <code>activate()</code>, the OpenBLAS fallback is fully removed.</p></li></ul>',22)])])}const x=e(l,[["render",a]]);export{y as __pageData,x as default};
